import json

USER_ID = "S17_baseline_test"

import json
from decimal import Decimal

def parse_raw(raw):
    samples = []

    for line in raw.strip().split("\n"):
        parts = line.split(",")

        if len(parts) < 9:
            continue

        try:
            samples.append({
                "subject": parts[0],
                "time_s": float(parts[1]),
                "label": int(parts[2]),
                "label_nome": parts[3],
                "hr": float(parts[4]),
                "ibi": float(parts[5]),
                "bvp": float(parts[6]),
                "temp": float(parts[7]),
                "acc_mag": float(parts[8]),
            })
        except:
            continue

    return samples


# -----------------------------
# CHUNK
# -----------------------------
def chunk(data, size=500):
    for i in range(0, len(data), size):
        yield i, data[i:i+size]


# -----------------------------
# MAIN
# -----------------------------
samples = parse_raw(raw_data)

print("Total samples:", len(samples))

for i, batch in chunk(samples, 500):

    payload = {
        "userId": USER_ID,
        "batchIndex": i,
        "samples": batch
    }

    filename = f"output_batch_{i}.json"

    with open(filename, "w", encoding="utf-8") as f:
        json.dump(payload, f, indent=2, ensure_ascii=False)

    print("gerado:", filename)

